ALTER TABLE gold.hechos_movimiento_personal NOCHECK CONSTRAINT ALL;
SET IDENTITY_INSERT gold.hechos_movimiento_personal ON;
TRUNCATE TABLE gold.hechos_movimiento_personal;
WITH fechas_parseadas AS (
    SELECT id_movimiento, id_efectivo, id_unidad_destino, id_rango, id_tipo,
        antiguedad_anios, salario_mensual, observaciones,
        CASE 
            WHEN fecha_movimiento NOT LIKE '%/%' AND fecha_movimiento NOT LIKE '%-%' THEN TRY_CONVERT(DATE, fecha_movimiento, 112)
            WHEN TRY_CONVERT(INT, LEFT(fecha_movimiento, 4)) >= 1900 AND fecha_movimiento LIKE '%/%' THEN TRY_CONVERT(DATE, fecha_movimiento, 111)
            WHEN fecha_movimiento LIKE '%/%' THEN TRY_CONVERT(DATE, fecha_movimiento, 103)
            WHEN TRY_CONVERT(INT, LEFT(fecha_movimiento, 2)) > 12 THEN TRY_CONVERT(DATE, fecha_movimiento, 105)
            WHEN TRY_CONVERT(INT, SUBSTRING(fecha_movimiento, 4, 2)) > 12 THEN TRY_CONVERT(DATE, fecha_movimiento, 110)
            ELSE TRY_CONVERT(DATE, fecha_movimiento, 105)
        END AS fecha_parsed
    FROM silver.movimientos_personal
)
INSERT INTO gold.hechos_movimiento_personal (id_movimiento, id_tiempo, id_efectivo, id_unidad_destino, id_rango, id_tipo_movimiento, antiguedad_anios, salario_mensual, observaciones)
SELECT p.id_movimiento, t.id_tiempo, p.id_efectivo, p.id_unidad_destino, p.id_rango, p.id_tipo, p.antiguedad_anios, p.salario_mensual, p.observaciones
FROM fechas_parseadas p INNER JOIN gold.dim_tiempo t ON t.fecha = p.fecha_parsed;
SET IDENTITY_INSERT gold.hechos_movimiento_personal OFF;
ALTER TABLE gold.hechos_movimiento_personal CHECK CONSTRAINT ALL;
